module counter(CLK, RST, UP, DOWN, COUNT);
input CLK, RST, UP, DOWN;
output [3:0] COUNT;
reg [3:0] COUNT;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge RST or posedge dbg_halt) begin
    if (RST)
        COUNT <= 0;
    else if (UP && DOWN)
        COUNT <= COUNT;
    else if (UP)
        COUNT <= COUNT + 1;
    else if (DOWN)
        COUNT <= COUNT - 1;
end

endmodule
